# -------------------- TCP CONNECTIONS --------------------
async def TcPOnLine(ip, port, AutHToKen, bot):
    try:
        reader, writer = await asyncio.open_connection(ip, int(port))
        bot.online_writer = writer
        writer.write(bytes.fromhex(AutHToKen))
        await writer.drain()
        print(f"✅ Bot {bot.uid} Online connected")
        while True:
            try:
                data = await reader.read(9999)
                if not data:
                    break
            except:
                break
    except Exception as e:
        print(f"❌ Online error for {bot.uid}: {e}")
    finally:
        bot.online_writer = None

async def TcPChaT(ip, port, AutHToKen, bot):
    try:
        reader, writer = await asyncio.open_connection(ip, int(port))
        bot.whisper_writer = writer
        writer.write(bytes.fromhex(AutHToKen))
        await writer.drain()
        print(f"✅ Bot {bot.uid} Chat connected")
        while True:
            try:
                data = await reader.read(9999)
                if not data:
                    break
            except:
                break
    except Exception as e:
        print(f"❌ Chat error for {bot.uid}: {e}")
    finally:
        bot.whisper_writer = None

